    const networkId = midnightJsNetworkId.getNetworkId();
    const walletCpkHex = midnightJsUtils.parseCoinPublicKeyToHex(walletCoinPublicKey, networkId);
    const localCpkHex = midnightJsUtils.parseCoinPublicKeyToHex(zswapState.coinPublicKey, networkId);
